#!/usr/bin/env python3
"""Audit the A002 modular DCC source candidate generated by Blender.

Run after the A002 generator has produced its component blend files:

    blender --background --python Tools/DCC/audit_bloodaxe_cairnstone_a002_modular_dcc_source_a01.py

The audit checks the Phase 3A boundaries: separate component identity,
component-local pivots, A002 source ownership, no UVs, no texture nodes, no FBX
or Unreal outputs, and proof-render presence.
"""

from __future__ import annotations

import json
from pathlib import Path

import bpy


ROOT = Path(__file__).resolve().parents[2]
ASSET_ID = "SM_GIA_BloodAxeCairnstone_A002"
PACKAGE_ID = f"{ASSET_ID}_ModularDCCSource_A01"
SOURCE_ROOT = (
    ROOT
    / "SourceAssets"
    / "Blender"
    / "Props"
    / "Giants"
    / "BloodAxe"
    / "Cairns"
    / PACKAGE_ID
)
AUTOMATION_ROOT = ROOT / "Saved" / "Automation" / "DCC" / ASSET_ID / "ModularDCCSourceA01"
PROOF_ROOT = AUTOMATION_ROOT / "ProofRenders"
MANIFEST_PATH = AUTOMATION_ROOT / f"{ASSET_ID}_ModularDCCSourceA01Manifest.json"
AUDIT_PATH = AUTOMATION_ROOT / f"{ASSET_ID}_ModularDCCSourceA01Audit.json"

EXPECTED_COMPONENTS = {
    "primary_monolith": {
        "asset_name": f"{ASSET_ID}_PrimaryMonolith",
        "center_px": [541, 1222],
        "blend_path": SOURCE_ROOT / f"{ASSET_ID}_PrimaryMonolith.blend",
    },
    "upper_socket_ring": {
        "asset_name": f"{ASSET_ID}_UpperSocketRing",
        "center_px": [528, 1223],
        "blend_path": SOURCE_ROOT / f"{ASSET_ID}_UpperSocketRing.blend",
    },
    "support_base": {
        "asset_name": f"{ASSET_ID}_SupportBase",
        "center_px": [528, 1223],
        "blend_path": SOURCE_ROOT / f"{ASSET_ID}_SupportBase.blend",
    },
}

PROOF_VIEWS = ("front", "back", "left", "right", "top", "angle")


def fail(message: str, failures: list[str]) -> None:
    failures.append(message)


def relative(path: Path) -> str:
    try:
        return str(path.relative_to(ROOT))
    except ValueError:
        return str(path)


def load_manifest(failures: list[str]) -> dict[str, object]:
    if not MANIFEST_PATH.exists():
        fail(f"Missing manifest: {relative(MANIFEST_PATH)}", failures)
        return {}
    try:
        manifest = json.loads(MANIFEST_PATH.read_text(encoding="utf-8"))
    except json.JSONDecodeError as exc:
        fail(f"Manifest is not valid JSON: {exc}", failures)
        return {}
    if manifest.get("asset_id") != ASSET_ID:
        fail("Manifest asset_id mismatch", failures)
    if manifest.get("package_id") != PACKAGE_ID:
        fail("Manifest package_id mismatch", failures)
    policy = manifest.get("core_policy", {})
    if not isinstance(policy, dict):
        fail("Manifest core_policy is missing or invalid", failures)
    else:
        for key in (
            "no_a001_generated_output_as_source",
            "no_a02_generated_output_as_source",
            "no_uv_generation",
            "no_texture_nodes",
            "no_fbx_export",
            "no_unreal_output",
            "no_component_merge",
            "no_cross_view_average",
        ):
            if policy.get(key) is not True:
                fail(f"Manifest core_policy.{key} is not true", failures)
    return manifest


def mesh_triangles(obj: bpy.types.Object) -> int:
    if obj.type != "MESH":
        return 0
    return sum(max(1, len(poly.vertices) - 2) for poly in obj.data.polygons)


def material_uses_texture_nodes(material: bpy.types.Material) -> bool:
    if not material.use_nodes:
        return False
    if not material.node_tree:
        return False
    return any(node.type == "TEX_IMAGE" for node in material.node_tree.nodes)


def blocked_image_datablocks() -> list[str]:
    internal_names = {"Render Result", "Viewer Node"}
    return sorted(image.name for image in bpy.data.images if image.name not in internal_names)


def audit_open_blend(component_id: str, expected: dict[str, object], failures: list[str]) -> dict[str, object]:
    blend_path = expected["blend_path"]
    if not isinstance(blend_path, Path):
        fail(f"{component_id}: invalid expected blend path", failures)
        return {}
    if not blend_path.exists():
        fail(f"{component_id}: missing blend {relative(blend_path)}", failures)
        return {"component_id": component_id, "blend_path": relative(blend_path), "exists": False}

    bpy.ops.wm.open_mainfile(filepath=str(blend_path))
    asset_name = str(expected["asset_name"])
    main_obj = bpy.data.objects.get(asset_name)
    if main_obj is None:
        fail(f"{component_id}: missing main object {asset_name}", failures)
    elif main_obj.type != "MESH":
        fail(f"{component_id}: main object is not a mesh", failures)
    elif any(abs(float(value)) > 0.0001 for value in main_obj.location):
        fail(f"{component_id}: main object origin is not component-local at 0,0,0", failures)

    mesh_objects = [obj for obj in bpy.data.objects if obj.type == "MESH"]
    font_objects = [obj for obj in bpy.data.objects if obj.type == "FONT"]
    if not mesh_objects:
        fail(f"{component_id}: no mesh objects found", failures)

    uv_violations: list[str] = []
    material_node_violations: list[str] = []
    image_texture_violations: list[str] = []
    for obj in mesh_objects:
        if len(obj.data.uv_layers) != 0:
            uv_violations.append(obj.name)
        for mat in obj.data.materials:
            if mat is None:
                continue
            if material_uses_texture_nodes(mat):
                material_node_violations.append(mat.name)
    image_texture_violations = blocked_image_datablocks()
    if uv_violations:
        fail(f"{component_id}: UV layers found on {uv_violations}", failures)
    if material_node_violations:
        fail(f"{component_id}: texture nodes found on {material_node_violations}", failures)
    if image_texture_violations:
        fail(f"{component_id}: image data blocks found {image_texture_violations}", failures)

    center_px = None if main_obj is None else main_obj.get("a002_center_px")
    expected_center = expected["center_px"]
    if main_obj is not None:
        try:
            parsed_center = json.loads(str(center_px))
        except json.JSONDecodeError:
            parsed_center = None
        if parsed_center != expected_center:
            fail(f"{component_id}: center pixel metadata mismatch", failures)
        if main_obj.get("a002_component_id") != component_id:
            fail(f"{component_id}: component metadata mismatch", failures)
        if "a002_source_authority" not in main_obj:
            fail(f"{component_id}: missing source authority metadata", failures)

    proof_reports: list[dict[str, object]] = []
    for view in PROOF_VIEWS:
        proof_path = PROOF_ROOT / f"{asset_name}_{view.title()}Proof.png"
        exists = proof_path.exists()
        proof_reports.append({"view": view, "path": relative(proof_path), "exists": exists})
        if not exists:
            fail(f"{component_id}: missing proof render {relative(proof_path)}", failures)

    return {
        "component_id": component_id,
        "asset_name": asset_name,
        "blend_path": relative(blend_path),
        "exists": True,
        "mesh_object_count": len(mesh_objects),
        "font_object_count": len(font_objects),
        "triangle_count_with_markers": sum(mesh_triangles(obj) for obj in mesh_objects),
        "uv_layer_count": sum(len(obj.data.uv_layers) for obj in mesh_objects),
        "texture_node_materials": material_node_violations,
        "image_data_blocks": image_texture_violations,
        "proof_renders": proof_reports,
    }


def audit_manifest_components(manifest: dict[str, object], failures: list[str]) -> None:
    components = manifest.get("components", [])
    if not isinstance(components, list):
        fail("Manifest components field is not a list", failures)
        return
    seen = {str(component.get("component_id")) for component in components if isinstance(component, dict)}
    expected = set(EXPECTED_COMPONENTS)
    missing = sorted(expected - seen)
    extra = sorted(seen - expected)
    if missing:
        fail(f"Manifest missing components: {missing}", failures)
    if extra:
        fail(f"Manifest has unexpected components: {extra}", failures)


def write_audit(report: dict[str, object]) -> None:
    AUTOMATION_ROOT.mkdir(parents=True, exist_ok=True)
    AUDIT_PATH.write_text(json.dumps(report, indent=2) + "\n", encoding="utf-8")


def main() -> int:
    failures: list[str] = []
    manifest = load_manifest(failures)
    if manifest:
        audit_manifest_components(manifest, failures)

    component_reports = [
        audit_open_blend(component_id, expected, failures)
        for component_id, expected in EXPECTED_COMPONENTS.items()
    ]

    output_blockers = [
        ROOT / "Content" / "Props" / "Giants" / "BloodAxe" / "Cairns" / ASSET_ID,
        ROOT / "SourceAssets" / "FBX" / ASSET_ID,
    ]
    for path in output_blockers:
        if path.exists():
            fail(f"Blocked downstream output exists during Phase 3 source audit: {relative(path)}", failures)

    report = {
        "asset_id": ASSET_ID,
        "package_id": PACKAGE_ID,
        "status": "pass" if not failures else "fail",
        "manifest_path": relative(MANIFEST_PATH),
        "component_reports": component_reports,
        "failures": failures,
    }
    write_audit(report)
    print(AUDIT_PATH)
    if failures:
        for item in failures:
            print(f"FAIL: {item}")
        return 1
    print("A002 modular DCC source candidate audit passed")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
